+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using System.Collections.Generic;
+using System.Linq;
+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public sealed class PaginatedListTests
+    {
+        [TestMethod]
+        public void Constructor_SetsPageIndex()
+        {
+            var items = new List<int> { 1, 2, 3 };
+            var list = new PaginatedList<int>(items, 10, 2, 3);
+            Assert.AreEqual(2, list.PageIndex);
+        }
+
+        [TestMethod]
+        public void Constructor_CalculatesTotalPages_WithRemainder()
+        {
+            var items = new List<int> { 1, 2, 3 };
+            var list = new PaginatedList<int>(items, 10, 1, 3);
+            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
+        }
+
+        [TestMethod]
+        public void Constructor_CalculatesTotalPages_ExactDivision()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
+            Assert.AreEqual(2, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_AddsItemsToList()
+        {
+            var items = new List<int> { 10, 20, 30 };
+            var list = new PaginatedList<int>(items, 30, 1, 10);
+            Assert.AreEqual(3, list.Count);
+            CollectionAssert.AreEqual(items, list);
+        }
+
+        [TestMethod]
+        public void Constructor_SingleItem_TotalPagesIsOne()
+        {
+            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
+            Assert.AreEqual(1, list.TotalPages);
+        }
+
+        [TestMethod]
+        [DataRow(1, false, DisplayName = "Page 1 has no previous")]
+        [DataRow(2, true, DisplayName = "Page 2 has previous")]
+        [DataRow(5, true, DisplayName = "Page 5 has previous")]
+        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);
+            Assert.AreEqual(expected, list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        [DataRow(1, 30, true, DisplayName = "Page 1 of 3 has next")]
+        [DataRow(3, 30, false, DisplayName = "Last page has no next")]
+        [DataRow(2, 30, true, DisplayName = "Middle page has next")]
+        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalCount, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, 10);
+            Assert.AreEqual(expected, list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_ReturnsCorrectPageOfItems()
+        {
+            var source = Enumerable.Range(1, 50).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 2, 10);
+
+            Assert.AreEqual(2, result.PageIndex);
+            Assert.AreEqual(5, result.TotalPages);
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(11, result[0]);
+            Assert.AreEqual(20, result[9]);
+        }
+
+        [TestMethod]
+        public void Create_FirstPage_StartsFromFirstItem()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(1, result.PageIndex);
+            Assert.AreEqual(3, result.TotalPages);
+            Assert.AreEqual(10, result.Count);
+            Assert.AreEqual(1, result[0]);
+        }
+
+        [TestMethod]
+        public void Create_LastPage_ReturnsRemainingItems()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 3, 10);
+
+            Assert.AreEqual(3, result.PageIndex);
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(21, result[0]);
+            Assert.AreEqual(25, result[4]);
+        }
+
+        [TestMethod]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = new List<int>().AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(0, result.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_PageSizeEqualToCount_SinglePage()
+        {
+            var source = Enumerable.Range(1, 10).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.AreEqual(10, result.Count);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_PageSizeLargerThanCount_SinglePage()
+        {
+            var source = Enumerable.Range(1, 5).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 100);
+
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.AreEqual(5, result.Count);
+        }
+
+        [TestMethod]
+        public void Create_PageSizeOne_ManyPages()
+        {
+            var source = Enumerable.Range(1, 5).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 3, 1);
+
+            Assert.AreEqual(5, result.TotalPages);
+            Assert.AreEqual(1, result.Count);
+            Assert.AreEqual(3, result[0]);
+            Assert.IsTrue(result.HasPreviousPage);
+            Assert.IsTrue(result.HasNextPage);
+        }
+    }
+}
