using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain any existing notifications from the static queue
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendNotification_EnqueuesNotification()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("TestUser", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("Chemistry"),
                $"Expected 'Chemistry' in message: {notification.Message}");
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("42"),
                $"Expected '42' in message: {notification.Message}");
        }

        [TestMethod]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            var notification = _sut.ReceiveNotification();
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsInFifoOrder()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", EntityOperation.UPDATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("Course", second.EntityType);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
            _sut.MarkAsRead(0);
            // No exception means success
        }

        [TestMethod]
        public void SendNotification_CreateOperation_MessageContainsCreated()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();
            Assert.IsTrue(notification.Message.Contains("created"),
                $"Expected 'created' in: {notification.Message}");
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_MessageContainsUpdated()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.UPDATE);
            var notification = _sut.ReceiveNotification();
            Assert.IsTrue(notification.Message.Contains("updated"),
                $"Expected 'updated' in: {notification.Message}");
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_MessageContainsDeleted()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
            var notification = _sut.ReceiveNotification();
            Assert.IsTrue(notification.Message.Contains("deleted"),
                $"Expected 'deleted' in: {notification.Message}");
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _sut.ReceiveNotification();
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} not between {before} and {after}");
        }

        [TestMethod]
        public void SendNotification_TwoArgOverload_EnqueuesNotification()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "User1");
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
        }

        [TestMethod]
        public void SendNotification_WithNullDisplayName_UsesIdFormat()
        {
            _sut.SendNotification("Student", "99", null, EntityOperation.CREATE, "Admin");
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("99"),
                $"Expected ID '99' in: {notification.Message}");
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
        {
            _sut.SendNotification("Student", "88", "", EntityOperation.CREATE, "Admin");
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("88"),
                $"Expected ID '88' in: {notification.Message}");
        }

        [TestMethod]
        public void ReceiveNotification_AfterMultipleSends_DrainsAllMessages()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            Assert.IsNotNull(_sut.ReceiveNotification());
            Assert.IsNotNull(_sut.ReceiveNotification());
            Assert.IsNotNull(_sut.ReceiveNotification());
            Assert.IsNull(_sut.ReceiveNotification());
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // No exception means success
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            service.Dispose();
            // No exception means success
        }
    }
}

