        public void Index_DefaultSort_SortsByLastNameAscending()
        {
            AddStudent("Zeta", "Z");
            AddStudent("Alpha", "A");
            AddStudent("Middle", "M");

            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Alpha", model[0].LastName);
            Assert.AreEqual("Middle", model[1].LastName);
            Assert.AreEqual("Zeta", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_SortsByLastNameDescending()
        {
            AddStudent("Alpha", "A");
            AddStudent("Zeta", "Z");

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Zeta", model[0].LastName);
            Assert.AreEqual("Alpha", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_SortsByEnrollmentDateAscending()
        {
            AddStudent("Late", "L", new DateTime(2024, 6, 1));
