            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(new DateTime(2024, 1, 1), model[0].EnrollmentDate);
            Assert.AreEqual(new DateTime(2024, 6, 1), model[1].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_SortsByEnrollmentDateDescending()
        {
            AddStudent("Early", "E", new DateTime(2024, 1, 1));
            AddStudent("Late", "L", new DateTime(2024, 6, 1));

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
