    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private NotificationsController _controller;
        private SchoolContext _context;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            TestHelper.SetupControllerContext(_controller);

            // Drain the static notification queue before each test
            var service = new ContosoUniversity.Services.NotificationService();
            while (service.ReceiveNotification() != null) { }
            service.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // --- Index Tests ---

        [TestMethod]
